+        runId === "slides-a" ? alphaPayload : runId === "slides-b" ? bravoPayload : null;
+      if (!payload) {
+        await route.fulfill({
+          status: 200,
+          headers: { "content-type": "text/event-stream" },
+          body: ["event: done", "data: {}", ""].join("\n"),
